%[text] # 例7.2 （LS法）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2026a
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example07_02"; % mfilename

imgname = "msipimg05";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');

figure(1)
subplot(1,3,1) %[output:5b8df63b]
imshow(X) %[output:5b8df63b]
title('原画像') %[output:5b8df63b]

% GPU へ転送
%X = gpuArray(X);
%%

import msip.*

% 分析処理
[LL1,HL1,LH1,HH1] = im53trans(X);
[LL2,HL2,LH2,HH2] = im53trans(LL1);
[LL3,HL3,LH3,HH3] = im53trans(LL2);

% ゾーン符号化
HH3 = 0*HH3;
HL2 = 0*HL2;
LH2 = 0*LH2;
HH2 = 0*HH2;
HL1 = 0*HL1;
LH1 = 0*LH1;
HH1 = 0*HH1;

% 合成処理
LL2 = im53itrans(LL3,HL3,LH3,HH3);
LL1 = im53itrans(LL2,HL2,LH2,HH2);
V = im53itrans(LL1,HL1,LH1,HH1);

% 結果表示
subplot(1,3,2) %[output:3ca81c72]
imshow(V) %[output:3ca81c72]
title("ゾーン符号化 (PSNR:"+num2str(psnr(X,V),"%6.3f")+" dB)") %[output:3ca81c72]
drawnow
imwrite(V,fullfile(resfolder,"fig07-02a.png"))
%%
%[text] ## 随伴関係の確認
%[text] $ \\langle \\mathbf{x},\\mathbf{Du} \\rangle = \\langle \\mathbf{D}^\\top\\mathbf{x},\\mathbf{u} \\rangle $
V = rand(size(X),'like',X); % v = Du -> u = D^{-1}v = Tv
a = dot(X(:),V(:));
[YLL,YHL,YLH,YHH] = imadj53itrans(X); % D'x
[ULL,UHL,ULH,UHH] = im53trans(V); % Tv
Y = cat(1,cat(2,YLL,YHL),cat(2,YLH,YHH));
U = cat(1,cat(2,ULL,UHL),cat(2,ULH,UHH));
b = dot(Y(:),U(:));
absdiff = max(abs(a-b));
assert(absdiff<1e-9,"随伴関係が成り立ちません: "+num2str(absdiff))
%
vpst = V;
lpre = 1.0;
err_ = Inf;
while ( err_ >  1e-9 ) % べき乗法
    % vpst = (A.'*A)*vpre
    vpre = vpst/norm(vpst(:));
    [LL1,HL1,LH1,HH1] = imadj53itrans(vpre);
    [LL2,HL2,LH2,HH2] = imadj53itrans(LL1);
    [LL3,HL3,LH3,HH3] = imadj53itrans(LL2);
    %[LL4,HL4,LH4,HH4] = imadj53itrans(LL3);
    %[LL5,HL5,LH5,HH5] = imadj53itrans(LL4);

    % S_I によるチャネル選択
    % 例：LL3,HL3,HL3 のみ残す
    %HL1(:) = 0; LH1(:) = 0; HH1(:) = 0;
    %HL2(:) = 0; LH2(:) = 0; HH2(:) = 0;
    %HL3(:) = 0; LH3(:) = 0; HH3(:) = 0;

    %LL4  = im53itrans(LL5,HL5,LH5,HH5);
    %LL3  = im53itrans(LL4,HL4,LH4,HH4);    
    LL2  = im53itrans(LL3,HL3,LH3,HH3);
    LL1  = im53itrans(LL2,HL2,LH2,HH2);
    vpst = im53itrans(LL1,HL1,LH1,HH1);
    n    = (vpst(:).'*vpst(:));
    d    = (vpst(:).'*vpre(:));
    lpst = n/d;
    %lpst = real(vpre(:)' * vpst(:)); % レイリー商
    err_ = norm(lpst-lpre);
    lpre = lpst;
end
sqrdNorm_D = lpst; % ||D||_S^2
fprintf('||D||_S^2 = %g\n',sqrdNorm_D); %[output:97cf6dda]
%[text] ## 
%%
%[text] ## 最小二乗法
nIters = 200; % 繰り返し回数
nLv = 3; % ツリー段数
%gain2d = 4; % HH フィルタのゲイン
kappa = 136; % sqrdNorm_D; % スペクトルノルム||D||_S の二乗
eta = 1/kappa; % (1-1e-3)*(2/kappa); % ステップサイズ

% 分析処理 c = D.'x
Z = zeros(size(X),'like',X);
[c_LL1,c_HL1,c_LH1,c_HH1] = imadj53itrans(Z);
[c_LL2,c_HL2,c_LH2,c_HH2] = imadj53itrans(c_LL1);
[c_LL3,c_HL3,c_LH3,c_HH3] = imadj53itrans(c_LL2);
% 係数更新 c ← y
y_LL3 = c_LL3;
y_HL3 = c_HL3;
y_LH3 = c_LH3;
for iter = 1:nIters
    % 合成処理 v = DS.'y
    y_LL2 = im53itrans(y_LL3,y_HL3,y_LH3,c_HH3);
    y_LL1 = im53itrans(y_LL2,c_HL2,c_LH2,c_HH2);
    V = im53itrans(y_LL1,c_HL1,c_LH1,c_HH1);

    % 随伴処理 z = D.'(v-x) = D.'(DS.'y-x)
    [z_LL1,z_HL1,z_LH1,z_HH1] = imadj53itrans(V-X);
    [z_LL2,z_HL2,z_LH2,z_HH2] = imadj53itrans(z_LL1);
    [z_LL3,z_HL3,z_LH3,z_HH3] = imadj53itrans(z_LL2);

    % 勾配 ∇f(y) = Sz = SD.'(DS.'y-x)
    grad_LL3 = z_LL3;
    grad_HL3 = z_HL3;
    grad_LH3 = z_LH3;
    %grad_HH3 = z_HH3;
    %grad_HL2 = z_HL2;
    %grad_LH2 = z_LH2;
    %grad_HH2 = z_HH2;

    % 係数更新 y ← y - μ∇f(y)
    y_LL3 = y_LL3 - eta*grad_LL3;
    y_HL3 = y_HL3 - eta*grad_HL3;
    y_LH3 = y_LH3 - eta*grad_LH3;
    %y_HH3 = y_HH3 - eta*grad_HH3;
    %y_HL2 = y_HL2 - eta*grad_HL2;
    %y_LH2 = y_LH2 - eta*grad_LH2;
    %y_HH2 = y_HH2 - eta*grad_HH2;

    % モニタリング
    if iter == 1
        subplot(1,3,3) %[output:0e59f59d]
        him = imshow(V);
        stt = "最小二乗法 ";
        htt = title(stt + "(t: " + num2str(iter) + ", PSNR:"+num2str(psnr(X,V),"%6.3f")+" dB)");
        drawnow
    elseif mod(iter,10)==0 
        him.CData = gather(V);
        htt.String = stt + "(t: " + num2str(iter) + ", PSNR:"+num2str(psnr(X,V),"%6.3f")+" dB)";
        drawnow
    end
end

% c = y
c_LL3 = y_LL3;
c_HL3 = y_HL3;
c_LH3 = y_LH3;
%c_HH3 = y_HH3;
%c_HL2 = y_HL2;
%c_LH2 = y_LH2;
%c_HH2 = y_HH2;

% 合成処理 v = DS.'c
c_LL2 = im53itrans(c_LL3,c_HL3,c_LH3,c_HH3);
c_LL1 = im53itrans(c_LL2,c_HL2,c_LH2,c_HH2);
V = im53itrans(c_LL1,c_HL1,c_LH1,c_HH1);

% 結果表示
him.CData = V; %[output:0e59f59d]
htt.String = stt + "(t: " + num2str(nIters) + ", PSNR:"+num2str(psnr(X,V),"%6.3f")+" dB)";
drawnow
imwrite(V,fullfile(resfolder,"fig07-02b.png"))

